mapper.select:
SELECT l.log_id, l.device_id, l.event_type, l.event_data, l.tenant_id, l.create_time
FROM iot_device_log l
WHERE l.tenant_id = #{tenantId}

    AND l.device_id = #{deviceId}


    AND l.event_type = #{eventType}

ORDER BY l.create_time DESC

SELECT l.log_id, l.device_id, l.event_type, l.event_data, l.tenant_id, l.create_time
FROM iot_device_log l
WHERE l.device_id = #{deviceId} AND l.tenant_id = #{tenantId}
ORDER BY l.create_time DESC
LIMIT #{limit}

